const DEDUCTIBLE = 100;
const CAP_MULTIPLIER = 2;

const INSURANCE_VALUES: Record<string, number> = {
  sword: 1000,
  amulet: 600,
  staff: 800,
  potion: 400,
  rune: 250,
  moonstone: 250,
};

export function claim(policy: ClaimPolicy, incident: ClaimIncident): ClaimResult {
  let payout = 0;
  for (const damage of incident.damages) {
    payout += damage.amount - DEDUCTIBLE;
  }

  let insuranceTotal = 0;
  for (const item of policy.items) {
    insuranceTotal += INSURANCE_VALUES[item.type];
  }
  const cap = CAP_MULTIPLIER * insuranceTotal;

  return { payout, remainingCap: cap - payout };
}
